          title: Row(
            children: [
              Text(entry.level.label,
                  style: const TextStyle(fontWeight: FontWeight.w600)),
              const SizedBox(width: 8),
              Text('${entry.timeSlot.emoji} $time',
                  style: TextStyle(fontSize: 12, color: Colors.grey.shade600)),
