    final now = _selectedDate;
    return _entries.where((e) =>
        e.timestamp.year == now.year &&
        e.timestamp.month == now.month &&
        e.timestamp.day == now.day).toList()
      ..sort((a, b) => a.timestamp.compareTo(b.timestamp));
  }

  @override
