        ? entriesForVehicle(vehicleName)
        : List<FuelEntry>.from(_entries)
      ..sort((a, b) => a.date.compareTo(b.date));

    if (list.isEmpty) {
      return const FuelStats(
        avgMpg: 0,
        avgPricePerGallon: 0,
        avgCostPerMile: 0,
        totalSpent: 0,
        totalGallons: 0,
        totalMiles: 0,
        fillUpCount: 0,
      );
    }

